void build(const std::vector<int>& arr, std::vector<int>& tree, int v, int tl, int tr) {
    if (tl == tr) {
        tree[v] = arr[tl];
    } else {
        int tm = (tl + tr) / 2;
        build(arr, tree, v*2, tl, tm);
        build(arr, tree, v*2+1, tm+1, tr);
        tree[v] = tree[v*2] + tree[v*2+1];
    }
}

int query_sum(const std::vector<int>& tree, int v, int tl, int tr, int l, int r) {
    if (l > r) return 0;
    if (l == tl && r == tr) return tree[v];
    int tm = (tl + tr) / 2;
    return query_sum(tree, v*2, tl, tm, l, std::min(r, tm)) + 
           query_sum(tree, v*2+1, tm+1, tr, std::max(l, tm+1), r);
}

