int jumpSearch(const std::vector<int>& arr, int x) {
    int n = arr.size();
    int step = std::sqrt(n);
    int prev = 0;
    while (arr[std::min(step, n) - 1] < x) {
        prev = step;
        step += std::sqrt(n);
        if (prev >= n) return -1;
    }
    while (arr[prev] < x) {
        prev++;
        if (prev == std::min(step, n)) return -1;
    }
    if (arr[prev] == x) return prev;
    return -1;
}

