matrix multiply(const matrix& A, const matrix& B) {
    int rA = A.size(), cA = A[0].size(), cB = B[0].size();
    matrix C(rA, std::vector<int>(cB, 0));
    for (int i = 0; i < rA; ++i) {
        for (int j = 0; j < cB; ++j) {
