    std::string T = "#";
    for(char c : s) { T += c; T += '#'; }
    int n = T.length();
    std::vector<int> P(n);
    int C = 0, R = 0;
    for (int i = 1; i < n - 1; i++) {
        int i_mirror = 2 * C - i;
        if (R > i) P[i] = std::min(R - i, P[i_mirror]);
        else P[i] = 0;
        while (T[i + 1 + P[i]] == T[i - 1 - P[i]]) P[i]++;
        if (i + P[i] > R) { C = i; R = i + P[i]; }
    }
    int maxLen = 0, centerIndex = 0;
    for (int i = 1; i < n - 1; i++) {
        if (P[i] > maxLen) { maxLen = P[i]; centerIndex = i; }
    }
    return s.substr((centerIndex - maxLen) / 2, maxLen);
}

