bool graphColoringUtil(int v, int m, int n, const std::vector<std::vector<bool>>& graph, std::vector<int>& color) {
    if (v == n) return true;
    for (int c = 1; c <= m; c++) {
        if (isSafeToColor(v, c, n, graph, color)) {
            color[v] = c;
            if (graphColoringUtil(v + 1, m, n, graph, color)) return true;
            color[v] = 0; // backtrack
