void restore(const std::string& s, int i, int part, std::string current, std::vector<std::string>& result) {
    if (i == s.size() && part == 4) {
        result.push_back(current.substr(0, current.size() - 1));
        return;
    }
    if (i >= s.size() || part >= 4) return;
    restore(s, i + 1, part + 1, current + s.substr(i, 1) + ".", result);
    if (i + 1 < s.size() && s[i] != '0')
        restore(s, i + 2, part + 1, current + s.substr(i, 2) + ".", result);
    if (i + 2 < s.size() && s[i] != '0' && stoi(s.substr(i, 3)) <= 255)
        restore(s, i + 3, part + 1, current + s.substr(i, 3) + ".", result);
}

