void topologicalSortUtil(int v, const std::vector<std::vector<int>>& adj, std::vector<bool>& visited, std::stack<int>& st) {
    visited[v] = true;
    for (int i : adj[v]) {
        if (!visited[i]) topologicalSortUtil(i, adj, visited, st);
    }
    st.push(v);
}

std::vector<int> topologicalSort(int V, const std::vector<std::vector<int>>& adj) {
    std::stack<int> st;
    std::vector<bool> visited(V, false);
    for (int i = 0; i < V; i++) {
        if (!visited[i]) topologicalSortUtil(i, adj, visited, st);
    }
    std::vector<int> result;
    while(!st.empty()) { result.push_back(st.top()); st.pop(); }
    return result;
}

struct ListNode { int val; ListNode *next; };

bool hasCycle(ListNode *head) {
    if (!head || !head->next) return false;
    ListNode *slow = head, *fast = head->next;
    while (slow != fast) {
        if (!fast || !fast->next) return false;
        slow = slow->next;
        fast = fast->next->next;
    }
    return true;
}

